import boto3
import os
import logging

log = logging.getLogger(__name__)


def setup_glacier_lifecycle(bucket: str = None, prefix: str = 'backups/', days: int = 90):
    """Configure S3 lifecycle rule to transition old backups to Glacier."""
    bucket = bucket or os.environ['S3_BACKUP_BUCKET']
    s3 = boto3.client('s3')
    s3.put_bucket_lifecycle_configuration(
        Bucket=bucket,
        LifecycleConfiguration={
            'Rules': [{
                'ID': 'archive-old-backups',
                'Status': 'Enabled',
                'Filter': {'Prefix': prefix},
                'Transitions': [
                    {'Days': days, 'StorageClass': 'GLACIER'}
                ],
                'Expiration': {'Days': days + 365}  # delete after 1 year in Glacier
            }]
        }
    )
    log.info('Lifecycle policy set: %s/%s* → Glacier after %d days', bucket, prefix, days)
